import { PaginatedResponse } from "@mercurjs/types"

export enum RequestStatus {
  DRAFT = "draft",
  PENDING = "pending",
  ACCEPTED = "accepted",
  REJECTED = "rejected",
}

export interface RequestCustomFields {
  id: string
  request_status: RequestStatus
  submitter_id: string | null
  reviewer_id: string | null
  reviewer_note: string | null
  created_at: Date
  updated_at: Date
}

export interface RequestEntityResponse {
  id: string
  custom_fields: RequestCustomFields
  [key: string]: unknown
}

export interface AdminRequestResponse {
  request: RequestEntityResponse
}

export type AdminRequestListResponse = PaginatedResponse<{
  requests: RequestEntityResponse[]
}>

export interface VendorRequestResponse {
  request: RequestEntityResponse
}

export type VendorRequestListResponse = PaginatedResponse<{
  requests: RequestEntityResponse[]
}>

import { createStep } from "@medusajs/framework/workflows-sdk"
import { ContainerRegistrationKeys, MedusaError } from "@medusajs/framework/utils"

import { RequestStatus } from "../../../types"

type ValidateRequestStatusStepInput = {
  alias: string
  entity_id: string
  expected_status: RequestStatus | RequestStatus[]
}

export const validateRequestStatusStep = createStep(
  "validate-request-status",
  async (input: ValidateRequestStatusStepInput, { container }) => {
    const query = container.resolve(ContainerRegistrationKeys.QUERY)

    const {
      data: [entity],
    } = await query.graph({
      entity: input.alias,
      fields: ["id", "custom_fields.*"],
      filters: { id: input.entity_id },
    })

    if (!entity) {
      throw new MedusaError(MedusaError.Types.NOT_FOUND, "Request not found")
    }

    const status = (entity as any).custom_fields?.request_status

    const expected = Array.isArray(input.expected_status)
      ? input.expected_status
      : [input.expected_status]

    if (!expected.includes(status)) {
      throw new MedusaError(
        MedusaError.Types.INVALID_DATA,
        `Request status must be ${expected.join(" or ")}, but is ${status}`
      )
    }
  }
)

import { createWorkflow, WorkflowResponse } from "@medusajs/framework/workflows-sdk"
import { upsertCustomFieldsStep } from "@mercurjs/core-plugin/workflows"

import { RequestStatus } from "../../../types"
import { validateRequestStatusStep } from "../steps"

type AcceptRequestWorkflowInput = {
  alias: string
  entity_id: string
  reviewer_id: string
  reviewer_note?: string
}

export const acceptRequestWorkflow = createWorkflow(
  "accept-request",
  (input: AcceptRequestWorkflowInput) => {
    validateRequestStatusStep({
      alias: input.alias,
      entity_id: input.entity_id,
      expected_status: RequestStatus.PENDING,
    })

    const result = upsertCustomFieldsStep({
      alias: input.alias,
      data: {
        id: input.entity_id,
        request_status: RequestStatus.ACCEPTED,
        reviewer_id: input.reviewer_id,
        reviewer_note: input.reviewer_note ?? null,
      },
    })

    return new WorkflowResponse(result)
  }
)

