import { createWorkflow, transform, WorkflowResponse } from "@medusajs/framework/workflows-sdk"
import { createCollectionsWorkflow } from "@medusajs/medusa/core-flows"
import { upsertCustomFieldsStep } from "@mercurjs/core-plugin/workflows"

import { RequestStatus } from "../../../types"

type CreateProductCollectionRequestWorkflowInput = {
  product_collection: {
    title: string
    handle?: string
    metadata?: Record<string, unknown>
  }
  submitter_id: string
}

export const createProductCollectionRequestWorkflow = createWorkflow(
  "create-product-collection-request",
  function (input: CreateProductCollectionRequestWorkflowInput) {
    const collections = createCollectionsWorkflow.runAsStep({
      input: {
        collections: [input.product_collection],
      },
    })

    const upsertInput = transform({ collections, input }, (data) => ({
      alias: "product_collection",
      data: {
        id: data.collections[0]!.id,
        request_status: RequestStatus.PENDING,
        submitter_id: data.input.submitter_id,
      },
    }))

    upsertCustomFieldsStep(upsertInput)

    const collection = transform({ collections }, (data) => data.collections[0]!)

    return new WorkflowResponse(collection)
  }
)

import { z } from "zod"
import { createFindParams, createOperatorMap } from "@medusajs/medusa/api/utils/validators"
import { RequestStatus } from "../../../types"

export type AdminGetRequestsParamsType = z.infer<typeof AdminGetRequestsParams>
export const AdminGetRequestsParams = createFindParams({
  offset: 0,
  limit: 50,
}).extend({
  request_status: z
    .union([z.nativeEnum(RequestStatus), z.array(z.nativeEnum(RequestStatus))])
    .optional(),
  submitter_id: z.union([z.string(), z.array(z.string())]).optional(),
  created_at: createOperatorMap().optional(),
  updated_at: createOperatorMap().optional(),
})

export type AdminReviewNoteType = z.infer<typeof AdminReviewNote>
export const AdminReviewNote = z.object({
  reviewer_note: z.string().optional(),
})

export const adminRequestFields = [
  "id",
  "name",
  "title",
  "handle",
  "value",
  "description",
  "is_active",
  "is_internal",
  "custom_fields.*",
  "created_at",
  "updated_at",
]

export const adminRequestQueryConfig = {
  list: {
    defaults: adminRequestFields,
    isList: true,
  },
  retrieve: {
    defaults: adminRequestFields,
    isList: false,
  },
}

import {
  validateAndTransformBody,
  validateAndTransformQuery,
} from "@medusajs/framework"
import { MiddlewareRoute } from "@medusajs/medusa"

import { adminRequestQueryConfig } from "./query-config"
import { AdminGetRequestsParams, AdminReviewNote } from "./validators"

export const adminRequestsMiddlewares: MiddlewareRoute[] = [
