import { StatusBadge, Text } from "@medusajs/ui";
import { DateCell, DateHeader } from "@mercurjs/dashboard-shared";
import { RequestDTO } from "../../api/requests";

const columnHelper = createColumnHelper<RequestDTO>();

const statusColor = (status: string) => {
  switch (status) {
    case "accepted":
      return "green" as const;
    case "pending":
      return "orange" as const;
    case "rejected":
      return "red" as const;
    default:
      return "grey" as const;
  }
};

export const useRequestTableColumns = (nameKey: string = "name") => {
  const { t } = useTranslation();

  return useMemo(
    () => [
      columnHelper.display({
        id: "display_name",
        header: () => (
          <div className="flex h-full w-full items-center">
            <span className="truncate">Name</span>
          </div>
        ),
        cell: ({ row }) => (
          <Text size="small" leading="compact">
            {row.original[nameKey] ?? row.original.id}
          </Text>
        ),
      }),
      columnHelper.accessor("custom_fields", {
        header: () => (
          <div className="flex h-full w-full items-center">
            <span className="truncate">Status</span>
          </div>
        ),
        cell: ({ getValue }) => {
          const customFields = getValue() as any;
          const status = customFields?.request_status ?? "draft";
          return (
            <StatusBadge color={statusColor(status)}>
              {status.charAt(0).toUpperCase() + status.slice(1)}
            </StatusBadge>
          );
        },
      }),
      columnHelper.accessor("created_at", {
        header: () => <DateHeader />,
        cell: ({ getValue }) => {
          const date = new Date(getValue() as string);
          return <DateCell date={date} />;
        },
      }),
    ],
    [t, nameKey],
  );
};

import { useTranslation } from "react-i18next";
import { useMemo } from "react";

import type { Filter } from "@mercurjs/dashboard-shared";

export const useRequestTableFilters = (): Filter[] => {
  const { t } = useTranslation();

  return useMemo(() => {
    const filters: Filter[] = [
      {
        key: "request_status",
        label: "Status",
        type: "select",
        multiple: true,
        options: [
          { label: "Draft", value: "draft" },
          { label: "Pending", value: "pending" },
          { label: "Accepted", value: "accepted" },
          { label: "Rejected", value: "rejected" },
        ],
      },
    ];

    const dateFilters: Filter[] = [
      { label: t("fields.createdAt"), key: "created_at" },
      { label: t("fields.updatedAt"), key: "updated_at" },
    ].map((f) => ({
      key: f.key,
      label: f.label,
      type: "date" as const,
    }));

    filters.push(...dateFilters);

    return filters;
  }, [t]);
};

import { useQueryParams } from "@mercurjs/dashboard-shared";

type UseRequestTableQueryProps = {
  prefix?: string;
  pageSize?: number;
};

export const useRequestTableQuery = ({
  prefix,
  pageSize = 20,
}: UseRequestTableQueryProps) => {
  const queryObject = useQueryParams(
    ["offset", "q", "created_at", "updated_at", "order", "request_status"],
    prefix,
  );

  const { offset, created_at, updated_at, q, order, request_status } = queryObject;

  const searchParams: Record<string, any> = {
    limit: pageSize,
    offset: offset ? Number(offset) : 0,
    created_at: created_at ? JSON.parse(created_at) : undefined,
    updated_at: updated_at ? JSON.parse(updated_at) : undefined,
    order: order ? order : "-created_at",
    request_status: request_status || undefined,
    q,
  };

  return {
    searchParams,
    raw: queryObject,
  };
};

