const DetailBreadcrumb = (props: UIMatch) => {
  const { type, id } = props.params || {};
  const { request } = useRequest(type!, id!, {
    enabled: Boolean(type && id),
  });

  if (!request) return null;

  const nameKey = ENTITY_NAME_KEY[type!] ?? "name";
  const name = (request as Record<string, any>)[nameKey];

  return <span>{name ?? id}</span>;
};

export const handle = {
  breadcrumb: (match: UIMatch) => <DetailBreadcrumb {...match} />,
};

const statusColor = (status: string) => {
  switch (status) {
    case "accepted":
      return "green" as const;
    case "pending":
      return "orange" as const;
    case "rejected":
      return "red" as const;
    default:
      return "grey" as const;
  }
};

const TYPE_LABELS: Record<string, string> = {
  product_category: "Category",
  product_collection: "Collection",
  product_tag: "Tag",
  product_type: "Type",
};

const ENTITY_FIELDS: Record<string, { key: string; label: string }[]> = {
  product_category: [
    { key: "name", label: "Name" },
    { key: "handle", label: "Handle" },
    { key: "description", label: "Description" },
    { key: "is_active", label: "Active" },
    { key: "is_internal", label: "Internal" },
  ],
  product_collection: [
    { key: "title", label: "Title" },
    { key: "handle", label: "Handle" },
  ],
  product_tag: [{ key: "value", label: "Value" }],
  product_type: [{ key: "value", label: "Value" }],
};

const ENTITY_NAME_KEY: Record<string, string> = {
  product_category: "name",
  product_collection: "title",
  product_tag: "value",
  product_type: "value",
};

const formatFieldValue = (key: string, value: unknown): string => {
  if (value === null || value === undefined) return "-";
  if (typeof value === "boolean") return value ? "Yes" : "No";
  return String(value);
};

const SectionRow = ({
  title,
  value,
}: {
  title: string;
  value?: string | null;
}) => (
  <div className="text-ui-fg-subtle grid grid-cols-2 items-center gap-4 px-6 py-4">
    <Text size="small" weight="plus" leading="compact">
      {title}
    </Text>
